mapper.select:
SELECT id, question, correct_answer, explanation, subject_id, category, type, difficulty, option1, option2, option3, option4, option5, is_ai_generated, programming_language FROM ( SELECT p.id, p.question, p.answer AS correct_answer, p.explanation, s.id AS subject_id, s.name AS category, p.type, p.difficulty, p.option1, p.option2, p.option3, p.option4, p.option5, p.is_ai_generated, NULL AS programming_language FROM problem p INNER JOIN subject s ON p.subject_id = s.id WHERE p.id = #{id}
UNION ALL
SELECT sp.id, sp.question, sp.answer AS correct_answer, sp.explanation, s.id AS subject_id, s.name AS category, 'SUBJECTIVE' AS type, sp.difficulty, NULL AS option1, NULL AS option2, NULL AS option3, NULL AS option4, NULL AS option5, FALSE AS is_ai_generated, NULL AS programming_language FROM subjective_problems sp INNER JOIN subject s ON sp.subject_id = s.id WHERE sp.id = #{id}
UNION ALL
SELECT pp.id, pp.question, pp.answer AS correct_answer, pp.explanation, s.id AS subject_id, s.name AS category, 'PROGRAMMING_LANGUAGE' AS type, pp.difficulty, NULL AS option1, NULL AS option2, NULL AS option3, NULL AS option4, NULL AS option5, FALSE AS is_ai_generated, pp.prog_language AS programming_language FROM programming_language_problems pp INNER JOIN subject s ON pp.subject_id = s.id WHERE pp.id = #{id} ) AS combined LIMIT 1

SELECT 'SUBJECTIVE' AS card_type, sp.id, sp.subject_id, sp.question AS front_text, sp.answer AS back_text, sp.explanation, sp.difficulty, sp.option1, sp.option2, sp.option3, sp.option4, sp.option5 FROM subjective_problems sp INNER JOIN subject s ON sp.subject_id = s.id WHERE s.name = #{category}
UNION ALL
SELECT 'FLASHCARD' AS card_type, lc.id, lc.subject_id, lc.front_text, lc.back_text, lc.explanation, 0 AS difficulty, NULL AS option1, NULL AS option2, NULL AS option3, NULL AS option4, NULL AS option5 FROM learning_card lc INNER JOIN subject s ON lc.subject_id = s.id WHERE s.name = #{category}
ORDER BY card_type, id

choose.otherwise:
SELECT p.id
FROM problem p
WHERE p.type = #{type}
ORDER BY RANDOM()
LIMIT #{limit}

mapper.select:
SELECT id FROM ( SELECT p.id, TRIM(s.name) AS cat FROM problem p INNER JOIN subject s ON p.subject_id = s.id UNION ALL SELECT id, prog_language AS cat FROM programming_language_problems ) t
t.cat NOT IN
#{category}
ORDER BY RANDOM() LIMIT #{limit}
